// Extract WhatsApp message data
const body = $input.first().json.body || $input.first().json;
const entry = body.entry?.[0];
const change = entry?.changes?.[0];
const message = change?.value?.messages?.[0];

if (!message) {
  return [{ json: { skip: true } }];
}

const phoneNumber = message.from;
const messageText = (message.text?.body || '').toLowerCase().trim();
const timestamp = new Date(parseInt(message.timestamp) * 1000);

// Business hours check (Europe/Madrid, UTC+2 in summer)
const madridOffset = 2; // adjust for DST if needed
const madridHour = (timestamp.getUTCHours() + madridOffset) % 24;
const madridMinute = timestamp.getUTCMinutes();
const isBusinessHours = (
  (madridHour > 8 || (madridHour === 8 && madridMinute >= 0)) &&
  (madridHour < 20 || (madridHour === 20 && madridMinute <= 30))
);

// Keyword check
const KEYWORDS = [
  'presupuesto','precio','cuánto','cuanto','cuesta','costaría',
  'reforma','pintura','pintar','acabado','estuco','microcemento',
  'presupest','preu'
];
const hasKeyword = KEYWORDS.some(kw => messageText.includes(kw));

return [{
  json: {
    phoneNumber,
    messageText: message.text?.body || '',
    isBusinessHours,
    hasKeyword,
    timestamp: timestamp.toISOString(),
    routeType: !isBusinessHours ? 'fuera_horario' : hasKeyword ? 'presupuesto' : 'general'
  }
}];

const phoneNumber = $input.first().json.phoneNumber;
const routeType = $input.first().json.routeType;

const MESSAGES = {
  fuera_horario: `¡Hola! 👋 Soy BCN Pro Reforma.\n\nHemos recibido tu mensaje. Nuestro horario es 8:00-20:30h. Te contactamos mañana a primera hora.\n\nMientras tanto, puedes ver nuestros servicios y calcular tu presupuesto aquí 👇\n🔗 https://bcnproreforma.com/#calculadora`,
  presupuesto: `¡Hola! 👋 Gracias por contactar con BCN Pro Reforma.\n\nSomos especialistas en pintura, reformas y acabados en Maresme y Barcelona.\n\nPara darte un presupuesto ajustado, calcula tu proyecto aquí:\n🔗 https://bcnproreforma.com/#calculadora\n\nO si prefieres, cuéntanos:\n1️⃣ ¿Qué tipo de trabajo necesitas? (pintura / reforma / acabados)\n2️⃣ ¿En qué municipio está el inmueble?\n3️⃣ ¿Cuántos m² aproximadamente?`,
  general: `¡Hola! 👋 BCN Pro Reforma aquí.\n\nRecibimos tu mensaje y te respondemos enseguida.\n\nPuedes ver todos nuestros servicios en:\n🔗 https://bcnproreforma.com`
};

return [{
  json: {
    ...($input.first().json),
    replyText: MESSAGES[routeType] || MESSAGES.general,
    waPayload: {
      messaging_product: 'whatsapp',
      recipient_type: 'individual',
      to: phoneNumber,
      type: 'text',
      text: { preview_url: false, body: MESSAGES[routeType] || MESSAGES.general }
    }
  }
}];

